final_source:
build for javascript backend

when user sends calc to /api/calculate:
  validate calc:
    a is number, required
    b is number, required
    operation is text, required

  result = 0

  if calc's operation is 'add':
    result is calc's a + calc's b
  else if calc's operation is 'subtract':
    result is calc's a - calc's b
  else if calc's operation is 'multiply':
    result is calc's a * calc's b
  else if calc's operation is 'divide':
    if calc's b is 0:
      send back 'Division by zero not allowed' with status 400
    result is calc's a / calc's b

  send back { result is result }
